1	use quote::quote;
2	use rust_i18n_support::{
3	    is_debug, load_locales, I18nConfig, DEFAULT_MINIFY_KEY, DEFAULT_MINIFY_KEY_LEN,
4	    DEFAULT_MINIFY_KEY_PREFIX, DEFAULT_MINIFY_KEY_THRESH,
5	};
6	use std::collections::BTreeMap;
7	use syn::{parse_macro_input, Expr, Ident, LitBool, LitStr, Token};
8	
9	mod minify_key;
10	mod tr;
11	
12	struct Args {
13	    locales_path: String,
14	    default_locale: Option<String>,
15	    fallback: Option<Vec<String>>,
16	    extend: Option<Expr>,
17	    minify_key: bool,
18	    minify_key_len: usize,
19	    minify_key_prefix: String,
20	    minify_key_thresh: usize,
21	}
22	
23	impl Args {
24	    fn consume_path(&mut self, input: syn::parse::ParseStream) -> syn::parse::Result<()> {
25	        let path = input.parse::<LitStr>()?;
26	        self.locales_path = path.value();
27	
28	        Ok(())
29	    }
30	
31	    fn consume_fallback(&mut self, input: syn::parse::ParseStream) -> syn::parse::Result<()> {
32	        if let Ok(val) = input.parse::<LitStr>() {
33	            self.fallback = Some(vec![val.value()]);
34	            return Ok(());
35	        }
36	        let val = input.parse::<syn::ExprArray>()?;
37	        let fallback = val
38	            .elems
39	            .into_iter()
40	            .map(|expr| {
41	                if let syn::Expr::Lit(syn::ExprLit {
42	                    lit: syn::Lit::Str(lit_str),
43	                    ..
44	                }) = expr
45	                {
46	                    Ok(lit_str.value())
47	                } else {
48	                    Err(input.error(
49	                        "`fallback` must be a string literal or an array of string literals",
50	                    ))
51	                }
52	            })
53	            .collect::<syn::parse::Result<Vec<String>>>()?;
54	        self.fallback = Some(fallback);
55	        Ok(())
56	    }
57	
58	    fn consume_minify_key(&mut self, input: syn::parse::ParseStream) -> syn::parse::Result<()> {
59	        let lit_bool = input.parse::<LitBool>()?;
60	        self.minify_key = lit_bool.value;
61	        Ok(())
62	    }
63	
64	    fn consume_minify_key_len(&mut self, input: syn::parse::ParseStream) -> syn::parse::Result<()> {
65	        let lit_int = input.parse::<syn::LitInt>()?;
66	        self.minify_key_len = lit_int.base10_parse()?;
67	        Ok(())
68	    }
69	
70	    fn consume_minify_key_prefix(
71	        &mut self,
72	        input: syn::parse::ParseStream,
73	    ) -> syn::parse::Result<()> {
74	        let lit_str = input.parse::<syn::LitStr>()?;
75	        self.minify_key_prefix = lit_str.value();
76	        Ok(())
77	    }
78	
79	    fn consume_minify_key_thresh(
80	        &mut self,
81	        input: syn::parse::ParseStream,
82	    ) -> syn::parse::Result<()> {
83	        let lit_int = input.parse::<syn::LitInt>()?;
84	        self.minify_key_thresh = lit_int.base10_parse()?;
85	        Ok(())
86	    }
87	
88	    fn consume_options(&mut self, input: syn::parse::ParseStream) -> syn::parse::Result<()> {
89	        let ident = input.parse::<Ident>()?.to_string();
90	        input.parse::<Token![=]>()?;
91	
92	        // If there have any option in arguments, it will override the config from metadata
93	        match ident.as_str() {
94	            "fallback" => {
95	                self.consume_fallback(input)?;
96	            }
97	            "backend" => {
98	                let val = input.parse::<Expr>()?;
99	                self.extend = Some(val);
100	            }
101	            "minify_key" => {
102	                self.consume_minify_key(input)?;
103	            }
104	            "minify_key_len" => {
105	                self.consume_minify_key_len(input)?;
106	            }
107	            "minify_key_prefix" => {
108	                self.consume_minify_key_prefix(input)?;
109	            }
110	            "minify_key_thresh" => {
111	                self.consume_minify_key_thresh(input)?;
112	            }
113	            _ => {}
114	        }
115	
116	        // Continue to consume reset of options
117	        if input.parse::<Token![,]>().is_ok() {
118	            self.consume_options(input)?;
119	        }
120	
121	        Ok(())
122	    }
123	
124	    /// Load the config from Cargo.toml. This can be overridden by subsequent options.
125	    fn load_metadata(&mut self, input: syn::parse::ParseStream) -> syn::parse::Result<()> {
126	        // CARGO_MANIFEST_DIR is current build directory
127	        if let Ok(cargo_dir) = std::env::var("CARGO_MANIFEST_DIR") {
128	            let current_dir = std::path::PathBuf::from(cargo_dir);
129	            let cfg = I18nConfig::load(&current_dir)
130	                .map_err(|_| input.error("Failed to load config from Cargo.toml for `metadata`"))?;
131	
132	            self.locales_path = cfg.load_path;
133	            self.default_locale = Some(cfg.default_locale.clone());
134	            if !cfg.fallback.is_empty() {
135	                self.fallback = Some(cfg.fallback);
136	            }
137	            self.minify_key = cfg.minify_key;
138	            self.minify_key_len = cfg.minify_key_len;
139	            self.minify_key_prefix = cfg.minify_key_prefix;
140	            self.minify_key_thresh = cfg.minify_key_thresh;
141	        } else if rust_i18n_support::is_debug() {
142	            return Err(input.error("The CARGO_MANIFEST_DIR is required fo `metadata`"));
143	        }
144	
145	        Ok(())
146	    }
147	}
