207	/// Init I18n translations.
208	///
209	/// This will load all translations by glob `**/*.yml` from the given path, default: `${CARGO_MANIFEST_DIR}/locales`.
210	///
211	/// # Attributes
212	///
213	/// - `fallback` for set the fallback locale, if present [`t!`](macro.t.html) macro will use it as the fallback locale.
214	/// - `backend` for set the backend, if present [`t!`](macro.t.html) macro will use it as the backend.
215	/// - `metadata` to enable/disable loading of the [package.metadata.i18n] config from Cargo.toml, default: `true`.
216	/// - `minify_key` for enable/disable minify key, default: [`DEFAULT_MINIFY_KEY`](constant.DEFAULT_MINIFY_KEY.html).
217	/// - `minify_key_len` for set the minify key length, default: [`DEFAULT_MINIFY_KEY_LEN`](constant.DEFAULT_MINIFY_KEY_LEN.html),
218	///   * The range of available values is from `0` to `24`.
219	/// - `minify_key_prefix` for set the minify key prefix, default: [`DEFAULT_MINIFY_KEY_PREFIX`](constant.DEFAULT_MINIFY_KEY_PREFIX.html).
220	/// - `minify_key_thresh` for set the minify key threshold, default: [`DEFAULT_MINIFY_KEY_THRESH`](constant.DEFAULT_MINIFY_KEY_THRESH.html).
221	///   * If the length of the value is less than or equal to this value, the value will not be minified.
222	///
223	/// ```no_run
224	/// # use rust_i18n::i18n;
225	/// # fn v1() {
226	/// i18n!();
227	/// # }
228	/// # fn v2() {
229	/// i18n!("locales");
230	/// # }
231	/// # fn v3() {
232	/// i18n!("locales", fallback = "en");
233	/// # }
234	/// # fn v4() {
235	/// i18n!("locales", fallback = ["en", "es"]);
236	/// # }
237	/// # fn v5() {
238	/// i18n!("locales", fallback = ["en", "es"],
239	///       minify_key = true,
240	///       minify_key_len = 12,
241	///       minify_key_prefix = "t_",
242	///       minify_key_thresh = 64);
243	/// # }
244	/// # fn v6() {
245	/// i18n!();
246	/// # }
247	/// ```
248	#[proc_macro]
249	pub fn i18n(input: proc_macro::TokenStream) -> proc_macro::TokenStream {
250	    let args = parse_macro_input!(input as Args);
251	
252	    // CARGO_MANIFEST_DIR is current build directory
253	    let cargo_dir = std::env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR is empty");
254	    let current_dir = std::path::PathBuf::from(cargo_dir);
255	    let locales_path = current_dir.join(&args.locales_path);
256	
257	    let data = load_locales(&locales_path.display().to_string(), |_| false);
258	    let code = generate_code(data, args);
259	
260	    if is_debug() {
261	        println!(
262	            "\n\n-------------- code --------------\n{}\n----------------------------------\n\n",
263	            code
264	        );
265	    }
