270	fn generate_code(
271	    translations: BTreeMap<String, BTreeMap<String, String>>,
272	    args: Args,
273	) -> proc_macro2::TokenStream {
274	    let all_translations = translations.iter().map(|(locale, translation)| {
275	        let translation_length = translation.len();
276	        let translation = translation.iter().map(
277	            |(k, v)| quote! { ::std::borrow::Cow::Borrowed(#k), ::std::borrow::Cow::Borrowed(#v) },
278	        );
279	        quote! {
280	            ::std::borrow::Cow::Borrowed(#locale),
281	            {
282	                let mut map = std::collections::HashMap::with_capacity(#translation_length);
283	                #(
284	                    map.insert(#translation);
285	                )*
286	                map
287	            }
288	        }
289	    });
290	    let all_translations = quote! {
291	        let mut backend  = rust_i18n::SimpleBackend::new();
292	
293	        #(
294	            backend.add_translations(#all_translations);
295	        )*
296	    };
297	
298	    let default_locale = if let Some(default_locale) = args.default_locale {
299	        quote! {
300	            use std::ops::Deref;
301	            if #default_locale != rust_i18n::locale().deref() {
302	                rust_i18n::set_locale(rust_i18n::locale().deref());
303	            } else {
304	                rust_i18n::set_locale(#default_locale);
305	            }
306	        }
307	    } else {
308	        quote! {}
309	    };
310	
311	    let fallback = if let Some(fallback) = args.fallback {
312	        quote! {
313	            Some(&[#(#fallback),*])
314	        }
315	    } else {
316	        quote! {
317	            None
318	        }
319	    };
320	
321	    let extend_code = if let Some(extend) = args.extend {
322	        quote! {
323	            let backend = backend.extend(#extend);
324	        }
325	    } else {
326	        quote! {}
327	    };
328	
329	    let minify_key = args.minify_key;
330	    let minify_key_len = args.minify_key_len;
331	    let minify_key_prefix = args.minify_key_prefix;
332	    let minify_key_thresh = args.minify_key_thresh;
333	
334	    quote! {
335	        use rust_i18n::{BackendExt, CowStr, MinifyKey};
336	
337	        /// I18n backend instance
338	        ///
339	        /// [PUBLIC] This is a public API, and as an example in examples/
340	        #[allow(missing_docs)]
341	        static _RUST_I18N_BACKEND: std::sync::LazyLock<Box<dyn rust_i18n::Backend>> = std::sync::LazyLock::new(|| {
342	            #all_translations
343	            #extend_code
344	            #default_locale
345	
346	            Box::new(backend)
347	        });
348	
349	        static _RUST_I18N_FALLBACK_LOCALE: Option<&[&'static str]> = #fallback;
350	        static _RUST_I18N_MINIFY_KEY: bool = #minify_key;
351	        static _RUST_I18N_MINIFY_KEY_LEN: usize = #minify_key_len;
352	        static _RUST_I18N_MINIFY_KEY_PREFIX: &str = #minify_key_prefix;
353	        static _RUST_I18N_MINIFY_KEY_THRESH: usize = #minify_key_thresh;
354	
355	        /// Lookup fallback locales
356	        ///
357	        /// For example: `"zh-Hant-CN-x-private1-private2"` -> `"zh-Hant-CN-x-private1"` -> `"zh-Hant-CN"` -> `"zh-Hant"` -> `"zh"`.
358	        ///
359	        /// https://datatracker.ietf.org/doc/html/rfc4647#section-3.4
360	        #[inline]
361	        #[doc(hidden)]
362	        #[allow(missing_docs)]
363	        pub fn _rust_i18n_lookup_fallback(locale: &str) -> Option<&str> {
364	            locale.rfind('-').map(|n| locale[..n].trim_end_matches("-x"))
365	        }
366	
367	        /// Get I18n text by locale and key
368	        #[inline]
369	        #[allow(missing_docs)]
370	        #[doc(hidden)]
371	        pub fn _rust_i18n_translate<'r>(locale: &str, key: &'r str) -> std::borrow::Cow<'r, str> {
372	            _rust_i18n_try_translate(locale, key).unwrap_or_else(|| {
373	                if locale.is_empty() {
374	                    key.into()
375	                } else {
376	                    format!("{}.{}", locale, key).into()
377	                }
378	            })
379	        }
380	
381	        /// Try to get I18n text by locale and key
382	        #[inline]
383	        #[doc(hidden)]
384	        #[allow(missing_docs)]
385	        pub fn _rust_i18n_try_translate<'r>(locale: &str, key: impl AsRef<str>) -> Option<std::borrow::Cow<'r, str>> {
386	            _RUST_I18N_BACKEND.translate(locale, key.as_ref())
387	                .or_else(|| {
388	                    let mut current_locale = locale;
389	                    while let Some(fallback_locale) = _rust_i18n_lookup_fallback(current_locale) {
390	                        if let Some(value) = _RUST_I18N_BACKEND.translate(fallback_locale, key.as_ref()) {
391	                            return Some(value);
392	                        }
393	                        current_locale = fallback_locale;
394	                    }
395	
396	                    _RUST_I18N_FALLBACK_LOCALE.and_then(|fallback| {
397	                        fallback.iter().find_map(|locale| _RUST_I18N_BACKEND.translate(locale, key.as_ref()))
398	                    })
399	                })
400	        }
401	
402	        #[inline]
403	        #[doc(hidden)]
404	        #[allow(missing_docs)]
405	        pub fn _rust_i18n_available_locales() -> Vec<std::borrow::Cow<'static, str>> {
406	            let mut locales = _RUST_I18N_BACKEND.available_locales();
407	            locales.sort();
408	            locales
409	        }
410	
411	        #[doc(hidden)]
412	        #[allow(unused_macros)]
413	        macro_rules! __rust_i18n_t {
414	            ($($all_tokens:tt)*) => {
415	                rust_i18n::_tr!($($all_tokens)*, _minify_key = #minify_key, _minify_key_len = #minify_key_len, _minify_key_prefix = #minify_key_prefix, _minify_key_thresh = #minify_key_thresh)
416	            }
417	        }
418	
419	        #[doc(hidden)]
420	        #[allow(unused_macros)]
421	        macro_rules! __rust_i18n_tkv {
422	            ($msg:literal) => {
423	                {
424	                    let val = $msg;
425	                    let key = rust_i18n::_minify_key!($msg, #minify_key_len, #minify_key_prefix, #minify_key_thresh);
426	                    (key, val)
427	                }
428	            }
429	        }
430	
431	        pub(crate) use __rust_i18n_t as _rust_i18n_t;
432	        pub(crate) use __rust_i18n_tkv as _rust_i18n_tkv;
433	    }
434	}
435	
436	/// A procedural macro that generates a translation key from a value.
437	#[proc_macro]
438	#[doc(hidden)]
439	pub fn _minify_key(input: proc_macro::TokenStream) -> proc_macro::TokenStream {
440	    parse_macro_input!(input as minify_key::MinifyKey).into()
441	}
442	
443	/// Export the `_tr!` macro for rust_i18n crate.
444	///
445	/// This macro first checks if a translation exists for the input string.
446	/// If it does, it returns the translated string.
447	/// If it does not, it returns the input value.
448	#[proc_macro]
449	#[doc(hidden)]
450	pub fn _tr(input: proc_macro::TokenStream) -> proc_macro::TokenStream {
451	    parse_macro_input!(input as tr::Tr).into()
452	}
